import{_ as n,c as i,o as t,ag as r}from"./chunks/framework.091VdYs-.js";const g=JSON.parse('{"title":"TinyBill","description":"","frontmatter":{"aside":true},"headers":[],"relativePath":"projekte/tinybill.md","filePath":"projekte/tinybill.md"}'),a={name:"projekte/tinybill.md"};function s(l,e,h,d,o,c){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="tinybill" tabindex="-1">TinyBill <a class="header-anchor" href="#tinybill" aria-label="Permalink to &quot;TinyBill&quot;">​</a></h1><p><strong>Web-Anwendung · Kostenlos · <a href="https://tinybill.de" target="_blank" rel="noreferrer">tinybill.de</a></strong></p><p>TinyBill ist ein Dokumentengenerator für Rechnungen, Angebote und allgemeine Geschäftsdokumente. Wer eine Rechnung stellen will – als Freelancer, kleines Unternehmen oder Einzelperson – findet selten ein Tool, das genau das macht was es soll, ohne monatliche Abonnementgebühren und ohne überkomplizierte Oberflächen. TinyBill ist die Antwort auf dieses Problem: kostenlos nutzbar, ohne Account, ohne Abo.</p><h2 id="wie-es-entstand" tabindex="-1">Wie es entstand <a class="header-anchor" href="#wie-es-entstand" aria-label="Permalink to &quot;Wie es entstand&quot;">​</a></h2><p>TinyBill ist direkt aus meiner Arbeit bei der Infokom GmbH hervorgegangen. Zwei Jahre habe ich dort an einem Full-Stack-System für die Finanzbuchhaltung gearbeitet – konkret: eine Webanwendung zur Verwaltung von Rechnungsdaten für sechzehn Mitarbeiter. Was nach einem kleinen Projekt klingt, war technisch anspruchsvoll. Rechnungsdaten haben eine eigene Komplexität, die man erst entdeckt, wenn man tief drin steckt: Steuersätze, Rundungsdifferenzen, Skontoregelungen, länderspezifische Formate, elektronische Rechnungsstandards wie ZUGFeRD und XRechnung. Ich habe in dieser Zeit mehr über Rechnungslegung gelernt als in allen Wirtschaftsfächern meines Abiturs zusammen.</p><p>Nach diesen zwei Jahren hatte ich eine Wissensbasis, die ich nicht einfach vergessen wollte. Gleichzeitig fiel mir auf, dass es keine befriedigende kostenlose Lösung für einfache Rechnungserstellung gibt – entweder zu teuer, zu komplex, oder mit schlechter UX. Das war der Auslöser für TinyBill.</p><h2 id="technische-grundlage" tabindex="-1">Technische Grundlage <a class="header-anchor" href="#technische-grundlage" aria-label="Permalink to &quot;Technische Grundlage&quot;">​</a></h2><p>Version 1 von TinyBill basiert auf Vaadin – einem Java-Framework, das Backend und Frontend direkt verbindet. Vaadin ist in der Entwicklerwelt nicht besonders populär, und das zu Unrecht. Für interne Business-Anwendungen, bei denen Java bereits im Backend läuft, ist es eine sehr produktive Wahl: man schreibt die gesamte Anwendungslogik in Java, und Vaadin übersetzt das in eine reaktive Benutzeroberfläche. Kein separates JavaScript-Frontend, kein REST-API-Overhead für jede Kleinigkeit. Die Infokom-Erfahrung hat mich gut mit Vaadin vertraut gemacht, und so war es die natürliche Wahl für einen schnellen Start.</p><p>Datenbankanbindung über Hibernate und JPA, PostgreSQL als Datenbank, Spring Security für die Authentifizierung. Der Standard-Stack, den ich aus Jahren täglicher Arbeit gut kenne.</p><h2 id="tinybill-version-2" tabindex="-1">TinyBill Version 2 <a class="header-anchor" href="#tinybill-version-2" aria-label="Permalink to &quot;TinyBill Version 2&quot;">​</a></h2><p>Version 2 ist ein kompletter Neustart – und mein aktuelles Lernprojekt für Kotlin. Die Entscheidung für einen Neustart kam nicht aus Unzufriedenheit mit Version 1, sondern aus einer architektonischen Überzeugung: ein monolithisches Frontend ist langfristig eine Einschränkung. Wer das Backend als reine API baut, kann darüber jedes beliebige Frontend legen – eine Webanwendung, ein mobiles Interface, ein Shopify-Plugin, was auch immer gebraucht wird.</p><p>Die Ziele für Version 2:</p><p><strong>API-first.</strong> Das Backend stellt eine sauber dokumentierte REST-API bereit. Kein Framework-spezifischer Rendering-Mechanismus, kein Vaadin-Overhead, kein UI-Code im Backend. Reines HTTP, klare Schnittstellen, OpenAPI-Dokumentation.</p><p><strong>Kotlin statt Java.</strong> Kotlin ist die Sprache, mit der ich gerade arbeiten will. Den besten Weg eine Sprache zu lernen ist, sie in einem echten Projekt einzusetzen – mit echten Nutzern, echten Fehlern, echten Anforderungen. TinyBill v2 ist mein Kotlin-Projekt. Was mich an Kotlin überzeugt: die Null-Safety zwingt zu explizitem Umgang mit dem, was fehlen kann. Data classes reduzieren Boilerplate dramatisch. Extension functions machen Code lesbar, ohne die Architektur aufzuweichen. Kotlin fühlt sich an wie Java, das von jemandem überarbeitet wurde, der die Schmerzpunkte kennt.</p><p><strong>Headless.</strong> Kein vorgegebenes Frontend in Version 2. Die API kann von verschiedenen Clients genutzt werden. Geplant ist zunächst eine Vue-Webanwendung als primärer Client, langfristig auch ein Angular-Frontend und möglicherweise ein Shopify-Plugin für kleinere Händler.</p><h2 id="was-tinybill-mir-beibringt" tabindex="-1">Was TinyBill mir beibringt <a class="header-anchor" href="#was-tinybill-mir-beibringt" aria-label="Permalink to &quot;Was TinyBill mir beibringt&quot;">​</a></h2><p>Neben den technischen Aspekten ist TinyBill auch ein Projekt, das mich zwingt, über Produktentscheidungen nachzudenken. Wer entscheidet, welche Features gebaut werden? Was ist wirklich nützlich für echte Nutzer, und was ist eine interessante technische Übung ohne praktischen Wert? Diese Fragen stelle ich mir bei TinyBill regelmäßig – und die Antworten fallen manchmal anders aus als erwartet.</p><p>Ein konkretes Beispiel: Ich hatte lange geplant, ZUGFeRD (einen Standard für elektronische Rechnungen mit eingebettetem XML) in Version 1 zu integrieren. Technisch interessant, gut dokumentiert. Dann habe ich Nutzer gefragt, ob sie das brauchen. Die Antwort war fast durchgehend: Nein. Was sie brauchten, war eine stabilere PDF-Generierung und eine bessere Vorschau. Das war ernüchternd und lehrreich zugleich. Ich habe die ZUGFeRD-Implementation auf unbestimmte Zeit zurückgestellt und mich auf die tatsächlich genutzten Features konzentriert.</p><hr><p><a href="https://tinybill.de" class="cv-download-link" target="_blank" rel="noreferrer">Zu TinyBill</a></p>',20)])])}const b=n(a,[["render",s]]);export{g as __pageData,b as default};
